#include <vector>
#include <algorithm>
#include <cmath>
#include <iostream>

/**
 * Calculates the minimum total cost to make indices forming a specific alternating pattern 
 * (starting at start_index) special, assuming this pattern yields the maximum possible number of special indices.
 * 
 * @param nums The input array.
 * @param start_index The starting index of the intended peaks (1 or 2).
 * @return The total operation cost.
 */
long long calculate_cost_for_pattern(const std::vector<long long>& nums, int start_index) {
    long long total_cost = 0;
    int n = nums.size();

    // The loop iterates over potential peak indices i = start_index, start_index + 2, ... up to n-2
    for (int i = start_index; i <= n - 2; i += 2) {
        // i is a peak candidate

        // Neighbors are i-1 and i+1. Since 0 < i < n-1, neighbors exist.
        long long L = nums[i-1];
        long long R = nums[i+1];

        // Required value must be strictly greater than both neighbors
        long long required_val = std::max(L, R) + 1;

        long long current_val = nums[i];

        // Calculate cost: max(0, required_val - current_val)
        if (required_val > current_val) {
            total_cost += required_val - current_val;
        }
    }
    return total_cost;
}

long long solve(std::vector<long long> nums) {
    int n = nums.size();

    // Constraints guarantee n >= 3, so there is at least one potential peak index (i=1).
    if (n < 3) {
        return 0;
    }

    // m = n - 2 is the number of potential peak locations {1, 2, ..., n-2}
    int m = n - 2;

    if (m % 2 != 0) {
        // Case 1: m is odd (n is odd). The unique maximum independent set is {1, 3, 5, ..., n-2}.
        // We only need to check the pattern starting at index 1.
        return calculate_cost_for_pattern(nums, 1);
    } else {
        // Case 2: m is even (n is even). There are two maximum independent sets:
        // S1 = {1, 3, 5, ..., n-3} (starts at 1)
        // S2 = {2, 4, 6, ..., n-2} (starts at 2)

        long long cost1 = calculate_cost_for_pattern(nums, 1);
        long long cost2 = calculate_cost_for_pattern(nums, 2);

        return std::min(cost1, cost2);
    }
}

