using namespace std;

/**
 * Helper function to calculate the minimum cost to make all selected indices 
 * (starting at 'start' and stepping by 2) special, assuming only the peak values are increased.
 */
long long calculate_cost(const vector<long long>& nums, int start) {
    int N = nums.size();
    long long current_cost = 0;

    // Iterate through indices i = start, start + 2, start + 4, ... up to N-2
    for (int i = start; i <= N - 2; i += 2) {
        // Since we assume neighbors are not modified, their values are nums[j].
        long long L = nums[i - 1];
        long long R = nums[i + 1];

        // Required height H for nums[i]
        // H must be strictly greater than both neighbors.
        long long H = max(L, R) + 1;

        // Cost contribution: increase needed if current height is less than required height
        if (H > nums[i]) {
            current_cost += (H - nums[i]);
        }
    }
    return current_cost;
}

long long solve(vector<long long> nums) {
    int N = nums.size();

    // If N < 3, there are no possible special indices (1 < i < N-1).
    if (N < 3) {
        return 0;
    }

    // The maximum number of special indices is achieved by picking non-adjacent indices.
    // We check the two most dense configurations: starting at index 1 or starting at index 2.

    // Case 1: Peaks are at 1, 3, 5, ...
    long long cost1 = calculate_cost(nums, 1);

    // Case 2: Peaks are at 2, 4, 6, ...
    // Only calculate this if index 2 is a valid potential index (i.e., N >= 4).
    long long cost2 = -1; // Use -1 as sentinel for invalid/uncalculated
    if (N >= 4) {
        cost2 = calculate_cost(nums, 2);
    } else {
        // If N=3, only index 1 is possible. cost2 remains irrelevant/infinite cost.
        cost2 = -1; 
    }

    if (cost2 == -1) {
        return cost1;
    }

    return min(cost1, cost2);
}

